#include <stdio.h>

int main() {
  int age = 20;
  float height = 1.75;
  char grade = 'A';
  printf("Age: %d\n", age);
  printf("Height: %.2f meters\n", height);
  printf("Grade: %c\n", grade);
  return 0;
}
// Output:
// Age: 20
// Height: 1.75 meters
// Grade: A

